// Method 1: Type "VIBE" anywhere (no input focused)
document.addEventListener("keydown", function(e){
  var tag = document.activeElement ? document.activeElement.tagName : "";
  if(tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT") return;
  if(e.key.length === 1) ceoKeyBuffer += e.key.toUpperCase();
  clearTimeout(ceoKeyTimer);
  ceoKeyTimer = setTimeout(function(){ ceoKeyBuffer = ""; }, 2000);
  if(ceoKeyBuffer.endsWith("VIBE")){
    ceoKeyBuffer = "";
    openDashLogin();
  }
});

