var currentTierEvent = "rawdeo";
function showTierTable(evKey, btn) {
  currentTierEvent = evKey;
  document.querySelectorAll("#dash-tier-event-tabs .dash-tab").forEach(function(b){ b.classList.remove("on"); });
  if (btn) btn.classList.add("on");
  renderTierTable();
}
function renderTierTable() {
  var ev = EVENTS[currentTierEvent];
  if (!ev || !ev.tiers) return;
  var tbody = document.getElementById("tier-table-body");
  var tfoot = document.getElementById("tier-table-foot");
  if (!tbody) return;
  var totalSold = 0, totalRev = 0, totalCap = 0;
  tbody.innerHTML = ev.tiers.map(function(t){
    var avail = t.capacity - t.sold;
    var pct = Math.round(t.sold / t.capacity * 100);
    var rev = t.price * t.sold;
    totalSold += t.sold; totalRev += rev; totalCap += t.capacity;
    var statusBadge = (t.soldout || avail <= 0)
      ? '<span style="background:rgba(255,68,68,.12);color:#ff4444;border:1px solid rgba(255,68,68,.2);font-size:8px;padding:2px 8px;border-radius:20px;font-family:\'JetBrains Mono\',monospace;">SOLD OUT</span>'
      : (avail <= 20
        ? '<span style="background:rgba(255,184,0,.1);color:#ffb800;border:1px solid rgba(255,184,0,.2);font-size:8px;padding:2px 8px;border-radius:20px;font-family:\'JetBrains Mono\',monospace;">POCOS</span>'
        : '<span style="background:rgba(57,255,20,.1);color:var(--green);border:1px solid rgba(57,255,20,.2);font-size:8px;padding:2px 8px;border-radius:20px;font-family:\'JetBrains Mono\',monospace;">ACTIVO</span>');
    return "<tr>"
      +"<td style='display:flex;align-items:center;gap:8px;padding:12px 16px;'>"
        +"<div style='width:8px;height:8px;border-radius:50%;background:"+t.color+";flex-shrink:0'></div>"
        +"<span style='font-family:\"Barlow Condensed\",sans-serif;font-size:13px;font-weight:700;text-transform:uppercase;'>"+t.name+"</span>"
      +"</td>"
      +"<td style='text-align:center;color:var(--gray);font-family:\"JetBrains Mono\",monospace;font-size:11px;'>"+(t.price===0?"Gratis":"$"+t.price)+"</td>"
      +"<td style='text-align:center;color:var(--green);font-family:\"Barlow Condensed\",sans-serif;font-size:16px;font-weight:900;'>"+t.sold+"</td>"
      +"<td style='text-align:center;color:"+(avail<=0?"#ff4444":avail<=20?"#ffb800":"var(--gray)")+";font-family:\"JetBrains Mono\",monospace;font-size:11px;'>"+avail+"</td>"
      +"<td style='text-align:center;padding:12px 16px;'>"
        +"<div style='display:flex;align-items:center;gap:6px;justify-content:center;'>"
          +"<div style='height:4px;width:60px;background:var(--bg4);border-radius:2px;overflow:hidden;'>"
            +"<div style='height:4px;width:"+pct+"%;background:"+t.color+";border-radius:2px;'></div>"
          +"</div>"
          +"<span style='font-family:\"JetBrains Mono\",monospace;font-size:10px;color:var(--gray);min-width:28px;'>"+pct+"%</span>"
        +"</div>"
      +"</td>"
      +"<td style='text-align:right;font-family:\"Barlow Condensed\",sans-serif;font-size:14px;font-weight:700;'>"+(t.price===0?"<span style='color:var(--gray)'>—</span>":"$"+rev.toLocaleString())+"</td>"
      +"<td style='text-align:center;'>"+statusBadge+"</td>"
      +"</tr>";
  }).join("");
  if (tfoot) {
    tfoot.innerHTML = "<tr style='background:var(--bg3);border-top:1px solid var(--border);'>"
      +"<td style='padding:10px 16px;font-family:\"Barlow Condensed\",sans-serif;font-size:13px;font-weight:800;text-transform:uppercase;color:var(--white);'>TOTAL</td>"
      +"<td></td>"
      +"<td style='text-align:center;color:var(--green);font-family:\"Barlow Condensed\",sans-serif;font-size:16px;font-weight:900;'>"+totalSold+"</td>"
      +"<td style='text-align:center;color:var(--gray);font-family:\"JetBrains Mono\",monospace;font-size:11px;'>"+(totalCap-totalSold)+"</td>"
      +"<td style='text-align:center;font-family:\"JetBrains Mono\",monospace;font-size:10px;color:var(--gray);'>"+(Math.round(totalSold/totalCap*100))+"%</td>"
      +"<td style='text-align:right;color:var(--green);font-family:\"Barlow Condensed\",sans-serif;font-size:16px;font-weight:900;'>$"+totalRev.toLocaleString()+"</td>"
      +"<td></td>"
      +"</tr>";
  }
}
