function orgShowTier(key,el){
  document.querySelectorAll('#org-sec-tiers .org-tier-tab').forEach(function(t){t.classList.remove('on');});
  el.classList.add('on');
  orgRenderTierDetail(key);
}
function orgRenderTierDetail(key){
  var t=ORG_TIERS[key];
  var pct=Math.round(t.sold/t.cap*100);
  var avail=t.cap-t.sold;
  var gross=t.sold*t.price;
  var feeTotal=t.sold*t.fee;
  var net=gross-feeTotal;
  var maxD=Math.max.apply(null,t.daily)||1;
  var maxH=Math.max.apply(null,t.hourly)||1;
  var html='<div class="org-stat-grid">';
  html+='<div class="org-stat"><div class="org-stat-label">Vendidas</div><div class="org-stat-val green">'+t.sold+'</div><div class="org-stat-sub">de '+t.cap+' capacidad</div><div class="org-stat-prog"><div class="org-stat-prog-fill" style="width:'+pct+'%;background:'+t.color+'"></div></div></div>';
  html+='<div class="org-stat"><div class="org-stat-label">Disponibles</div><div class="org-stat-val '+(avail===0?'red':'')+'">'+avail+'</div><div class="org-stat-sub">'+(avail===0?'<span style="color:#ff4444">Agotado</span>':pct+'% vendido')+'</div></div>';
  html+='<div class="org-stat"><div class="org-stat-label">Precio</div><div class="org-stat-val">'+(t.price===0?'Gratis':'$'+t.price)+'</div><div class="org-stat-sub">+ $'+t.fee+' fee VIBE.</div></div>';
  html+='<div class="org-stat"><div class="org-stat-label">Ingresos brutos</div><div class="org-stat-val green">'+(t.price===0?'—':'$'+gross.toLocaleString())+'</div></div>';
  html+='<div class="org-stat"><div class="org-stat-label">Fee VIBE.</div><div class="org-stat-val" style="font-size:16px;color:var(--gray);">'+(t.price===0?'—':'$'+feeTotal.toLocaleString())+'</div></div>';
  html+='<div class="org-stat"><div class="org-stat-label">Neto organizador</div><div class="org-stat-val green">'+(t.price===0?'—':'$'+net.toLocaleString())+'</div></div>';
  html+='</div>';
  html+='<div class="org-charts-grid">';
  // Bar chart
  html+='<div class="org-chart-box"><div class="org-chart-title">Ventas por día (primeros 15 días)</div><div class="org-bar-chart">';
  t.daily.forEach(function(v){var h=Math.round((v/maxD)*100);html+='<div class="org-bc-col"><div class="org-bc-bar" style="height:'+Math.max(h,3)+'%;background:'+t.color+';opacity:'+(h>0?'0.85':'0.2')+'"></div></div>';});
  html+='</div><div style="display:flex;justify-content:space-between;font-family:\'JetBrains Mono\',monospace;font-size:8px;color:var(--gray2);margin-top:4px;"><span>Día 1</span><span>Día 15</span></div></div>';
  // Line chart
  var w=200,lh=55,pts=t.hourly.length;
  var polyPts=t.hourly.map(function(v,i){return ((i/(pts-1))*w)+','+(lh-(v/maxH)*(lh-4));}).join(' ');
  var fillArr=t.hourly.map(function(v,i){return ((i/(pts-1))*w)+','+(lh-(v/maxH)*(lh-4));});
  fillArr.unshift('0,'+lh);fillArr.push(w+','+lh);
  html+='<div class="org-chart-box"><div class="org-chart-title">Distribución por hora (hoy)</div>';
  html+='<svg viewBox="0 0 '+w+' '+lh+'" preserveAspectRatio="none" style="width:100%;height:55px;display:block;">';
  html+='<polygon points="'+fillArr.join(' ')+'" fill="'+t.color+'" opacity="0.1"/>';
  html+='<polyline points="'+polyPts+'" fill="none" stroke="'+t.color+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
  html+='</svg><div style="display:flex;justify-content:space-between;font-family:\'JetBrains Mono\',monospace;font-size:8px;color:var(--gray2);margin-top:4px;"><span>00:00</span><span>12:00</span><span>23:59</span></div></div>';
  // Donut
  var r=28,cx=32,cy=32,circ=2*Math.PI*r,dash=(t.sold/t.cap)*circ;
  html+='<div class="org-chart-box"><div class="org-chart-title">Capacidad usada</div><div class="org-donut-wrap">';
  html+='<svg width="64" height="64" viewBox="0 0 64 64" style="flex-shrink:0;"><circle cx="32" cy="32" r="28" fill="none" stroke="var(--bg4)" stroke-width="8"/><circle cx="32" cy="32" r="28" fill="none" stroke="'+t.color+'" stroke-width="8" stroke-dasharray="'+dash.toFixed(1)+' '+circ+'" stroke-dashoffset="'+(circ/4).toFixed(1)+'" stroke-linecap="round"/><text x="32" y="33" text-anchor="middle" dominant-baseline="middle" fill="'+t.color+'" font-size="11" font-family="JetBrains Mono" font-weight="700">'+pct+'%</text></svg>';
  html+='<div><div class="org-dl-item"><div class="org-dl-dot" style="background:'+t.color+'"></div><span>Vendidas</span><span style="margin-left:8px;color:var(--gray);">'+t.sold+'</span></div>';
  html+='<div class="org-dl-item"><div class="org-dl-dot" style="background:var(--bg4);border:1px solid var(--border)"></div><span>Disponibles</span><span style="margin-left:8px;color:var(--gray);">'+avail+'</span></div>';
  html+='<div class="org-dl-item" style="border-top:1px solid var(--border);padding-top:5px;margin-top:3px;"><span style="color:var(--gray);">Total '+t.cap+'</span></div></div></div></div>';
  // Payments
  html+='<div class="org-chart-box"><div class="org-chart-title">Métodos de pago</div>';
  t.payMethods.forEach(function(p){html+='<div class="org-pay-bar-row"><div class="org-pay-label">'+p.n+'</div><div class="org-pay-bar-bg"><div class="org-pay-bar-fill" style="width:'+p.p+'%;background:'+p.c+'"></div></div><div class="org-pay-pct">'+p.p+'%</div></div>';});
  html+='</div></div>';
  // Actions
  html+='<div class="org-act-row">';
  if(!t.soldout) html+='<button class="org-act-btn">⬡ Generar cortesías</button>';
  html+='<button class="org-act-btn gray">↓ CSV este tier</button>';
  if(!t.soldout) html+='<button class="org-act-btn gray">+ Aumentar capacidad</button>';
  html+='</div>';
  if(!t.soldout){
    html+='<div class="org-cort-panel"><div class="org-cort-title">Generar cortesías — '+t.name+'</div>';
    html+='<div class="org-slider-row"><div class="org-slider-label">Cantidad (1–50)</div><input type="range" min="1" max="50" value="10" style="flex:1;accent-color:var(--green);" oninput="this.nextElementSibling.textContent=this.value"/><div class="org-slider-num">10</div></div>';
    html+='<div class="org-cort-row"><input class="org-cort-input" type="text" placeholder="Etiqueta (ej. Staff, Prensa, Sponsor)"/><button class="org-gen-btn">Generar PDF →</button></div></div>';
  }
  html+='<div style="font-family:\'JetBrains Mono\',monospace;font-size:8px;color:var(--gray2);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:8px;">Compradores — '+t.name+'</div>';
  html+='<div style="overflow-x:auto;"><table class="org-table"><thead><tr><th>Comprador</th><th>Código</th><th>Método</th><th>Fecha</th><th>QR</th><th></th></tr></thead><tbody>';
  t.buyers.forEach(function(b){
    var initials=b.name.split(' ').slice(0,2).map(function(n){return n[0];}).join('');
    var bid=ORG_BUYERS.find(function(x){return x.email===b.email;});
    var bid2=bid?bid.id:'';
    html+='<tr><td><div class="org-buyer-cell"><div class="org-avatar" style="background:'+t.color+'22;color:'+t.color+';">'+initials+'</div><div><div class="org-buyer-name">'+b.name+'</div><div class="org-buyer-email">'+b.email+'</div></div></div></td>';
    html+='<td><span class="org-mono">'+b.code+'</span></td>';
    html+='<td>'+b.pay+'</td><td>'+b.date+'</td>';
    html+='<td><span class="org-badge '+(b.used?'ob-used':'ob-ok')+'">'+(b.used?'Usado':'Válido')+'</span></td>';
    html+='<td><button class="org-view-btn" onclick="orgOpenFromTier(\''+bid2+'\')">Ver perfil →</button></td></tr>';
  });
  html+='</tbody></table></div>';
  document.getElementById('org-tier-detail').innerHTML=html;
}
function orgOpenFromTier(id){
  if(!id) return;
  // switch to compradores tab
  document.querySelectorAll('.org-nav-item').forEach(function(n){n.classList.remove('on');});
  document.querySelectorAll('.org-section').forEach(function(s){s.classList.remove('active');});
  document.querySelectorAll('.org-nav-item')[2].classList.add('on');
  document.getElementById('org-sec-compradores').classList.add('active');
  orgRenderBuyers(ORG_BUYERS);
  orgOpenProfile(id);
}
