function orgRenderBuyers(list){
  var html='';
  list.forEach(function(b){
    var initials=b.name.split(' ').slice(0,2).map(function(n){return n[0];}).join('');
    var t=b.tickets[0];
    html+='<tr style="cursor:pointer;" onclick="orgOpenProfile(\''+b.id+'\')">';
    html+='<td><div class="org-buyer-cell"><div class="org-avatar" style="background:'+b.color+';color:'+b.textColor+';">'+initials+'</div><div><div class="org-buyer-name">'+b.name+'</div><div class="org-buyer-email">'+b.email+'</div></div></div></td>';
    html+='<td>'+b.tel.replace('+506 ','')+'</td>';
    html+='<td><span class="org-badge '+t.badge+'">'+t.tier+'</span></td>';
    html+='<td><span class="org-mono">'+t.code+'</span></td>';
    html+='<td>'+t.method+'</td><td>'+t.date+'</td>';
    html+='<td><span class="org-badge '+(t.used?'ob-used':'ob-ok')+'">'+(t.used?'Usado':'Válido')+'</span></td>';
    html+='<td><button class="org-view-btn" onclick="event.stopPropagation();orgOpenProfile(\''+b.id+'\')">Ver perfil →</button></td>';
    html+='</tr>';
  });
  var tbody=document.getElementById('org-buyers-tbody');
  if(tbody) tbody.innerHTML=html;
}
function orgFilterBuyers(q){
  if(!q){orgRenderBuyers(ORG_BUYERS);return;}
  var f=ORG_BUYERS.filter(function(b){
    return b.name.toLowerCase().includes(q.toLowerCase())||b.email.toLowerCase().includes(q.toLowerCase())||
    b.tickets.some(function(t){return t.code.toLowerCase().includes(q.toLowerCase());});
  });
  orgRenderBuyers(f);
}
function orgOpenProfile(id){
  var b=ORG_BUYERS.find(function(x){return x.id===id;});
  if(!b) return;
  var initials=b.name.split(' ').slice(0,2).map(function(n){return n[0];}).join('');
  var t=b.tickets[0];
  document.getElementById('op-avatar').textContent=initials;
  document.getElementById('op-avatar').style.background=b.color;
  document.getElementById('op-avatar').style.color=b.textColor;
  document.getElementById('op-name').textContent=b.name;
  document.getElementById('op-id').textContent=b.id+' · Member since '+b.since;
  document.getElementById('op-tier-badge').textContent='🎫 '+t.tier;
  document.getElementById('op-pay-badge').textContent='💳 '+b.favPay;
  document.getElementById('op-date-badge').textContent='📅 '+t.date;
  document.getElementById('op-spent').textContent=b.totalSpent;
  document.getElementById('op-tickets').textContent=b.totalTickets;
  document.getElementById('op-events').textContent=b.totalEvents;
  document.getElementById('op-fav-pay').textContent=b.favPay;
  document.getElementById('op-email').textContent=b.email;
  document.getElementById('op-tel').textContent=b.tel;
  document.getElementById('op-since').textContent=b.since;
  document.getElementById('op-qr-code').textContent=t.code;
  document.getElementById('op-qr-tier').textContent=t.tier+' · RAWDEO 2';
  if(t.used){
    document.getElementById('op-qr-status-text').innerHTML='<span style="color:#ff4444;font-weight:700;">✕ QR QUEMADO</span>';
    document.getElementById('op-qr-meta').textContent='Escaneado el Jun 6, 2026 · 21:14 · Staff iPhone';
    document.getElementById('op-qr-status-badge').innerHTML='<span class="org-badge ob-sold">USADO</span>';
    var bb=document.getElementById('op-burn-btn'); if(bb) bb.style.display='none';
  } else {
    document.getElementById('op-qr-status-text').innerHTML='<span style="color:var(--green);font-weight:700;">✓ QR VÁLIDO</span>';
    document.getElementById('op-qr-meta').textContent='No ha sido escaneado · Listo para ingresar al evento';
    document.getElementById('op-qr-status-badge').innerHTML='<span class="org-badge ob-ok">VÁLIDO</span>';
    var bb2=document.getElementById('op-burn-btn'); if(bb2) bb2.style.display='flex';
  }
  var histHtml='';
  b.tickets.forEach(function(tk){
    histHtml+='<tr><td style="color:var(--white);">'+tk.event+'</td>';
    histHtml+='<td><span class="org-badge '+tk.badge+'">'+tk.tier+'</span></td>';
    histHtml+='<td><span class="org-mono">'+tk.code+'</span></td>';
    histHtml+='<td style="color:var(--green);">'+tk.total+'</td>';
    histHtml+='<td>'+tk.method+'</td><td>'+tk.date+'</td>';
    histHtml+='<td><span class="org-badge '+(tk.used?'ob-used':'ob-ok')+'">'+(tk.used?'Usado':'Válido')+'</span></td></tr>';
  });
  document.getElementById('op-hist-tbody').innerHTML=histHtml;
  document.getElementById('op-hist-count').textContent=b.tickets.length+' compra'+(b.tickets.length>1?'s':'');
  document.getElementById('org-list-wrap').classList.add('hide');
  document.getElementById('org-profile-wrap').classList.add('show');
}
